// Ball-in-Cage — the classic captive-ball desk toy: a loose sphere trapped
// inside an OPEN cube frame, rattling freely but unable to escape.
// Technique (DISPLAY model, not a verified print-in-place): build the cage and
// the ball as two SEPARATE, non-touching solids and union them for rendering.
// >1 component is EXPECTED and correct here — the ball is deliberately captive,
// floating inside the frame with a visible clearance gap on every side.
//
// Cage: start from an outer cube, then punch a square window through each of the
// 6 faces by subtracting a smaller box per axis. What remains is the 12 SLENDER
// edge struts + 8 small corner blocks — a wireframe-like cage where the windows
// dominate each face. Each window opening is kept SMALLER than the ball diameter
// so the ball can never slip out — that's what makes it captive.
const { Manifold } = api;

const p = api.params({
  cageSize: { type: 'number', default: 44,  min: 30, max: 60, step: 1,   unit: 'mm', label: 'Cage outer size' },
  strut:    { type: 'number', default: 3.5, min: 2,  max: 8,  step: 0.5, unit: 'mm', label: 'Strut thickness' },
  window:   { type: 'number', default: 32,  min: 16, max: 48, step: 1,   unit: 'mm', label: 'Window opening' },
  ball:     { type: 'number', default: 17,  min: 8,  max: 26, step: 0.5, unit: 'mm', label: 'Ball radius' },
});

const S = p.cageSize;          // outer cube edge length
const t = p.strut;             // strut thickness (frame bar width) — kept slender

// Window opening: clamp so the struts always stay intact (at least `t` of frame
// on each side) AND so a window is never wider than the cage interior. The user
// knob is honored within those structural bounds. With slender struts the window
// can be large — most of each face is open.
const maxWindow = S - 2 * t;
const win = Math.max(4, Math.min(p.window, maxWindow));

// --- Cage: outer cube minus a square window punched through each of 3 axes ---
// A single through-cut of cross-section (win × win), made long enough to clear
// the cube on both ends, removes the face material on the two opposite faces it
// passes through. Three orthogonal cuts open all 6 faces, leaving thin edge
// struts + small corner blocks.
const outer = Manifold.cube([S, S, S], true);
const through = S + 2;         // longer than the cube so the cut fully penetrates

const cutZ = Manifold.cube([win, win, through], true);            // opens top + bottom faces
const cutX = Manifold.cube([through, win, win], true);            // opens +X / -X faces
const cutY = Manifold.cube([win, through, win], true);            // opens +Y / -Y faces

const cage = outer.subtract(cutZ).subtract(cutX).subtract(cutY);

// --- Captive ball: centered sphere, sized between the window and the cavity ---
// CAPTIVE GUARANTEE: radius is clamped so the ball stays strictly larger than
// half the window opening (so its diameter exceeds the window → it can't slip
// out) yet strictly smaller than the strut cage (so it floats free without
// touching the bars, leaving a visible clearance gap).
//   • Lower bound: r > win/2  → diameter 2r > win → can't escape a window.
//   • Upper bound: the nearest strut material to the centre is the inner edge of
//     an edge bar, at radial distance sqrt(2)·(S/2 - t). Keep the ball a
//     `clearance` short of that so it never contacts a strut.
// Defaults sanity check: win 32, S 44, t 3.5 →
//   rMin = 32/2 + 1.5 = 17.5 ... but diameter must exceed win, and r=17 gives
//   2r = 34 > 32 ✓. strutReach = √2·(22−3.5) ≈ 26.16, rMax = 24.66, r=17 < 24.66 ✓.
const clearance = 1.5;                              // visible gap to the struts
const strutReach = Math.SQRT2 * (S / 2 - t);        // distance to nearest strut inner edge
const rMax = strutReach - clearance;                // largest ball that floats free
const rMin = win / 2 + 0.5;                          // smallest captive ball (diameter > window)
const r = Math.max(rMin, Math.min(p.ball, rMax));

const ball = Manifold.sphere(r);                // inherits the user's quality preset

// Cage one color, captive ball a bright contrasting color. labeledUnion keeps
// both labels (and therefore both colors) intact through the boolean. The two
// solids never touch, so this stays 2 components by design — that's the whole
// point of a captive-ball toy.
return api.labeledUnion([
  { name: 'cage', shape: cage, color: '#2b8cff' },
  { name: 'ball', shape: ball, color: '#ffd21f' },
]);

